import java.util.*;

class Solution {
    public int[] sumOfIntervals(int[] arr) {
        int n = arr.length;
        List<ArrayList<Integer>> indices = new ArrayList<>(101);
        for (int i = 0; i < 101; i++) {
            indices.add(new ArrayList<>());
        }
        int[] intervals = new int[n];

        for (int i = 0; i < n; ++i) {
            indices.get(arr[i]).add(i);
        }

        for (int i = 0; i < n; ++i) {
            for (int index : indices.get(arr[i])) {
                intervals[i] += Math.abs(index - i);
            }
        }

        return intervals;
    }
}
```

